import sys
from sys import stdin

def solve():
    input_data = stdin.buffer.read().split()
    idx = 0
    t = int(input_data[idx]); idx+=1

    for _ in range(t):
        n, m = int(input_data[idx]), int(input_data[idx+1]); idx+=2

        edges = []
        for i in range(n-1):
            x,y,v = int(input_data[idx]),int(input_data[idx+1]),int(input_data[idx+2]); idx+=3
            edges.append((x,y,v))

        queries = []
        for i in range(m):
            a,b,p = int(input_data[idx]),int(input_data[idx+1]),int(input_data[idx+2]); idx+=3
            queries.append((a,b,p))

        parent = list(range(n+1))
        rnk = [0]*(n+1)

        def find(x):
            if parent[x]==x: return x,0
            root,r = find(parent[x])
            rnk[x] ^= rnk[parent[x]]
            parent[x] = root
            return root, rnk[x]

        sys.setrecursionlimit(300000)

        def union(x,y,p):
            rx,dx = find(x)
            ry,dy = find(y)
            if rx==ry:
                return (dx^dy)==p
            parent[rx]=ry
            rnk[rx]=dx^dy^p
            return True

        ok = True

        # First pass: union all known edges
        for (x,y,v) in edges:
            if v>=0:
                p = bin(v).count('1')%2
                if not union(x,y,p):
                    ok=False

        # Union unknown edges with parity 0 (default)
        for (x,y,v) in edges:
            if v<0:
                union(x,y,0)

        if ok:
            for (a,b,p) in queries:
                if not union(a,b,p):
                    ok=False; break

        if not ok:
            print("NO")
            continue

        print("YES")
        out = []
        for i,(x,y,v) in enumerate(edges):
            if v>=0:
                out.append(f"{x} {y} {v}")
            else:
                rx,dx=find(x); ry,dy=find(y)
                needed_parity = dx^dy
                # Output a value with the needed parity
                out.append(f"{x} {y} {needed_parity}")
        print('\n'.join(out))

